class Solution {
    public int largestRectangleInHistogram(int[] data) {
        int maxArea = 0;
        int n = data.length;
        int[] left = new int[n];
        int[] right = new int[n];
        Stack<Integer> stack = new Stack<>();
        for (int i = 0; i < n; i++) {
            while (!stack.isEmpty() && data[stack.peek()] >= data[i]) {
                stack.pop();
            }
            left[i] = stack.isEmpty() ? -1 : stack.peek();
            stack.push(i);
        }
        stack.clear();
        for (int i = n - 1; i >= 0; i--) {
            while (!stack.isEmpty() && data[stack.peek()] >= data[i]) {
                stack.pop();
            }
            right[i] = stack.isEmpty() ? n : stack.peek();
            stack.push(i);
        }
        for (int i = 0; i < n; i++) {
            maxArea = Math.max(maxArea, data[i] * (right[i] - left[i] - 1));
        }
        return maxArea;
    }
}

