    public int largestRectangleInHistogram(int[] data) {
        int maxArea = 0;
        int n = data.Length;
        Stack<int> stack = new Stack<int>();

        for (int i = 0; i < n; i++) {
            while (stack.Count > 0 && data[stack.Peek()] > data[i]) {
                int height = data[stack.Pop()];
                int width = stack.Count == 0 ? i : i - stack.Peek() - 1;
                maxArea = Math.Max(maxArea, height * width);
            }
            stack.Push(i);
        }

        while (stack.Count > 0) {
            int height = data[stack.Pop()];
            int width = stack.Count == 0 ? n : n - stack.Peek() - 1;
            maxArea = Math.Max(maxArea, height * width);
        }

        return maxArea;
    }
}
